server.tool(
  "gallery_report_to_parent",
  `Report progress or completion back to the parent task. Adds a comment to the parent task's activity feed and optionally updates this task's status.

Use this when you're working on a delegated subtask and need to send updates or results back to the admin agent.`,
  {
    taskTitle: external_exports3.string().describe("Title of your current (child) task"),
    report: external_exports3.string().describe("Progress report or completion summary"),
    status: external_exports3.enum(["todo", "in_progress", "in_review", "done"]).optional().describe("Optionally update this task's status"),
    agentName: external_exports3.string().describe("Your agent name")
  },
  async (args) => {
    const tasks = await convexQuery("mcpInternal:listTasks", {});
    const matches = tasks.filter((t) => t.title.toLowerCase() === args.taskTitle.toLowerCase());
    if (matches.length === 0) return { content: [{ type: "text", text: `Task "${args.taskTitle}" not found.` }], isError: true };
    if (matches.length > 1) {
      const list = matches.map((t) => `- "${t.title}" (${t.status}, id: ${t._id})`).join("\n");
      return { content: [{ type: "text", text: `Multiple tasks match "${args.taskTitle}":
${list}
Please use a more specific title.` }], isError: true };
    }
    const childTask = matches[0];
    if (!childTask.parentTaskId) return { content: [{ type: "text", text: `Task "${args.taskTitle}" has no parent task.` }], isError: true };
    const result = await convexMutation("mcpInternal:reportToParent", {
      taskId: childTask._id,
      report: args.report,
      childStatus: args.status,
      agentName: args.agentName
    });
    return { content: [{ type: "text", text: `Reported to parent task "${result.parentTaskTitle}": ${args.report.slice(0, 200)}` }] };
  }
);
